PREFIX : <http://ambrosia.example.org/hospitality#>
PREFIX p: <http://ambrosia.example.org/hospitality/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?name ?customer_reviews ?number_of_stars WHERE {
  ?r a :Reviews .
  ?h a :Hotels .
  ?r p:hasHotels ?h .
  ?h p:name ?name .
  ?r p:Customer_Reviews ?customer_reviews .
  ?r p:Number_Of_Stars ?number_of_stars .
} }
  component: { SELECT ?name ?number_of_stars WHERE {
  ?r a :Reviews .
  ?h a :Hotels .
  ?r p:hasHotels ?h .
  ?h p:name ?name .
  ?r p:Number_Of_Stars ?number_of_stars .
} }
  component_2: { SELECT ?name ?customer_reviews WHERE {
  ?r a :Reviews .
  ?h a :Hotels .
  ?r p:hasHotels ?h .
  ?h p:name ?name .
  ?r p:Customer_Reviews ?customer_reviews .
} }
}

